INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '6f63158f-c48f-4234-bad5-0630ab7f71ff',
  '00000000-0000-0000-0000-000000000001',
  $escape$MLflow Model Registry — Versioning, Staging, and Approval Workflows$escape$,
  $escape$MLflow's Model Registry gives every registered model a versioned lineage tied directly to your experiment runs. When you call `mlflow.register_model()`, MLflow creates a new version under the model's namespace and sets its stage to `None`. From there, you transition versions through three built-in stages: `Staging`, `Production`, and `Archived`.

Use `MlflowClient.transition_model_version_stage()` to move a version programmatically, or gate it behind a CI check before promotion. A typical workflow: train → register → auto-promote to `Staging` → run integration tests → manually approve to `Production`. You can attach descriptions and tags at the version level (`set_model_version_tag`) to encode approval metadata — reviewer name, test suite SHA, or deployment target.

MLflow doesn't ship a native approval UI, so teams wire the promotion step into GitHub Actions or a webhook that calls the client API only after a human approval step passes. Archive old `Production` versions immediately after promotion to keep the stage unambiguous and avoid shadow deployments.$escape$,
  $escape$import mlflow
from mlflow.tracking import MlflowClient

client = MlflowClient()

# Register model from a completed run
model_uri = f"runs:/{run_id}/model"
mv = mlflow.register_model(model_uri, "fraud-detector")

# Tag with approval metadata
client.set_model_version_tag("fraud-detector", mv.version, "approved_by", "sravan")

# Promote to Staging, archive previous Production
client.transition_model_version_stage("fraud-detector", mv.version, stage="Staging")

# After tests pass, promote to Production
client.transition_model_version_stage(
    "fraud-detector", mv.version, stage="Production",
    archive_existing_versions=True
)$escape$,
  $escape$python$escape$,
