INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'b81b4b30-b8b5-4fd3-8658-7da368f1220c',
  '00000000-0000-0000-0000-000000000001',
  $escape$MLflow Model Monitoring — Catching Drift and Degradation in Prod$escape$,
  $escape$MLflow's Model Registry and Evaluate API give you the primitives to build a production monitoring loop without a separate MLOps platform. Tag deployed model versions with `client.set_model_version_tag(name, version, 'baseline_run_id', run_id)` to anchor your drift comparisons. On a schedule, call `mlflow.evaluate()` with `baseline_model=baseline_run_uri` and a fresh sample of production data — MLflow computes statistical drift metrics (PSI, KS test for numeric features, chi-squared for categoricals) and surfaces them as `mlflow.metrics` automatically when you pass `evaluators=['default']`. For prediction drift, log a custom metric via `mlflow.log_metric('prediction_drift_psi', psi_score)` inside your monitoring run. Performance degradation is tracked by comparing `metric.f1_score` across runs using `mlflow.search_runs(filter_string='tags.monitoring_type = "prod"', order_by=['metrics.f1_score ASC'])`. If the delta exceeds a threshold, programmatically transition the model stage: `client.transition_model_version_stage(name, version, 'Archived')`. Wire this into a GitHub Actions cron or Airflow DAG for a closed-loop degradation response system.$escape$,
  $escape$import mlflow
from mlflow.tracking import MlflowClient

client = MlflowClient()

with mlflow.start_run(tags={"monitoring_type": "prod"}) as run:
    results = mlflow.evaluate(
        model=f"models:/my-model/Production",
        data=prod_sample_df,
        targets="label",
        model_type="classifier",
        baseline_model=f"runs:/{baseline_run_id}/model",
        evaluators=["default"],
    )
    f1 = results.metrics["f1_score"]
    mlflow.log_metric("f1_score", f1)

    if f1 < 0.75:
        client.transition_model_version_stage("my-model", "1", "Archived")$escape$,
  $escape$python$escape$,
