INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'd1cd06da-3a74-4e31-8b70-9d5ada402f6a',
  '00000000-0000-0000-0000-000000000001',
  $escape$MLflow CI/CD — Automated Retraining, Evaluation Gates, and Model Deployment Pipelines$escape$,
  $escape$MLflow's Model Registry is the backbone of a production ML CI/CD loop. When a retraining job completes, log the run with `mlflow.log_metrics()` and register via `MlflowClient.create_model_version()`. The evaluation gate lives in your pipeline: query the current `Production` model's metrics using `client.get_latest_versions(name, stages=['Production'])`, then compare challenger vs. champion on held-out eval data. Only call `client.transition_model_version_stage(name, version, 'Production')` if the challenger wins on your gating metric — say, F1 > 0.02 delta. Wire this logic into GitHub Actions or Azure Pipelines as a post-training step. Use `mlflow.evaluate()` with a custom `EvaluationMetric` to enforce thresholds declaratively — it raises `MlflowException` on failure, naturally breaking the pipeline. Tag versions with `client.set_model_version_tag()` to annotate git SHA, dataset hash, and retraining trigger. This gives you full lineage: every `Production` transition is traceable to a specific commit, data snapshot, and eval result — no manual promotion, no blind deployments.$escape$,
  $escape$import mlflow
from mlflow.tracking import MlflowClient

client = MlflowClient()
MODEL_NAME = "churn-classifier"
GATE_METRIC = "f1_score"
MIN_DELTA = 0.02

def promote_if_better(challenger_run_id: str):
    challenger = client.get_run(challenger_run_id).data.metrics[GATE_METRIC]
    prod_versions = client.get_latest_versions(MODEL_NAME, stages=["Production"])
    if not prod_versions:
        stage = "Production"
    else:
        champion = client.get_run(
            client.get_model_version_download_uri(MODEL_NAME, prod_versions[0].version)
        )
        prod_f1 = client.get_run(prod_versions[0].run_id).data.metrics[GATE_METRIC]
        stage = "Production" if challenger >= prod_f1 + MIN_DELTA else "Archived"

    version = mlflow.register_model(f"runs:/{challenger_run_id}/model", MODEL_NAME)
    client.transition_model_version_stage(MODEL_NAME, version.version, stage)
    client.set_model_version_tag(MODEL_NAME, version.version, "promoted_by", "ci-pipeline")
    return stage$escape$,
  $escape$python$escape$,
