INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '914a20fe-fea0-4baf-967b-e9d7c26ea15c',
  '00000000-0000-0000-0000-000000000001',
  $escape$MLflow Pipelines — Encoding Drift Detection into Your Feature Engineering Steps$escape$,
  $escape$MLflow Pipelines (via the `mlflow.pipelines` module) structures feature engineering as discrete, logged steps — but most teams miss that each step's outputs are versioned artifacts you can diff across runs. Use `mlflow.log_metric()` inside your transform step to emit distribution statistics (mean, std, null rate) per feature, then compare them programmatically with `mlflow.search_runs()` against your baseline run. For data validation, hook into the `transform` step's `transformer_fn` to raise `MlflowException` on schema violations before they silently corrupt downstream training. Drift detection becomes a first-class citizen when you log a `drift_score` metric — computed via Jensen-Shannon divergence between the current batch's feature distributions and the reference dataset stored as an `mlflow.data.from_pandas()` dataset artifact. Tag each run with `mlflow.set_tag('data_version', hash)` so you can filter `search_runs(filter_string="tags.data_version != 'abc123'")` to isolate runs trained on drifted data. This turns your pipeline history into an auditable data health log.$escape$,
  $escape$import mlflow
import mlflow.data
from scipy.spatial.distance import jensenshannon
import numpy as np

def transform_step(df, reference_df):
    with mlflow.start_run(nested=True):
        for col in df.select_dtypes('number').columns:
            ref_hist, bins = np.histogram(reference_df[col].dropna(), bins=20, density=True)
            cur_hist, _ = np.histogram(df[col].dropna(), bins=bins, density=True)
            drift = jensenshannon(ref_hist + 1e-10, cur_hist + 1e-10)
            mlflow.log_metric(f"drift_{col}", drift)
            mlflow.log_metric(f"null_rate_{col}", df[col].isna().mean())

        dataset = mlflow.data.from_pandas(df, name="transformed_features")
        mlflow.log_input(dataset, context="transform")
        mlflow.set_tag("data_version", str(hash(df.to_json())))
    return df$escape$,
  $escape$python$escape$,
